parameters.text:
=Score this incoming lead:

Background: {{ $json.background }}
Track Interest: {{ $json.trackInterest }}
Source: {{ $json.source }}
Full Name: {{ $json.fullName }}
Submitted At: {{ $json.submittedAt }}

Apply the scoring rules exactly. Return only the JSON object.

parameters.jsCode:
const aiText = $input.first().json.output || $input.first().json.text || $input.first().json.content || '';
let cleaned = aiText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
let parsed;
try { parsed = JSON.parse(cleaned); } catch(e) { parsed = { score: 5, tier: 'WARM', reason: 'Parse error: ' + e.message }; }
const lead = $('Map Lead Fields').first().json;
return [{ json: { ...lead, score: parsed.score, tier: parsed.tier, reason: parsed.reason } }];

